---@param id string
function GiveRelic(id)
    pickup = game.itemInterpreter.GetPickupById(id)
    pickup.Execute("onPickup", nil)
end

--- @param Obj GameObject
--- @param id string
--- @return boolean
function ChangeRelicOutcome(Obj, id)
    if Obj == nil or id == nil or id == "" then
        return false
    end

    local itemUpgrade = nil
    local okComponent = pcall(function()
        itemUpgrade = Obj.GetComponent_ItemUpgrade_()
    end)
    if not okComponent or itemUpgrade == nil then
        return false
    end

    local okSet = pcall(function()
        itemUpgrade.forceSpawn = id
    end)
    return okSet
end

local function ClampInt(value, minValue, maxValue)
    if value < minValue then
        return minValue
    end
    if value > maxValue then
        return maxValue
    end
    return value
end

local function EnsureIntSetting(key, defaultValue)
    local sentinel = -2147483600
    local loaded = game.LoadInt(key, sentinel)
    if loaded == sentinel then
        game.SaveInt(key, defaultValue)
        return defaultValue
    end
    return loaded
end

local function EnsureAndClampInt(key, defaultValue, minValue, maxValue)
    local value = EnsureIntSetting(key, defaultValue)
    value = ClampInt(value, minValue, maxValue)
    game.SaveInt(key, value)
    return value
end

local function GetPlayerLiving()
    if game.playerLiving ~= nil then
        return game.playerLiving
    end
    if game.playerController ~= nil then
        return game.playerController.playerLiving
    end
    return nil
end

local SHOOT_MODE_KEY       = "MTS-Shoot-Mode"
local SHOOT_FORCE_KEY      = "MTS-Shoot-Force"
local SHOOT_FORCE_DEFAULT  = 200   -- stored as tenths (200 = 20.0 units/s)
local SHOOT_FORCE_MIN      = 10    -- 1.0
local SHOOT_FORCE_MAX      = 5000  -- 500.0

local SHOOT_TICK_INTERVAL  = 0.04  -- seconds per manual-move tick (~25 fps)
local SHOOT_MAX_TICKS      = 250   -- max ticks before giving up on manual move

local function RebuildFavoritesListFromSet()
    local list = {}
    for objectName, isFav in pairs(MTS_FAVORITES_SET) do
        if isFav and spawnablesLookup[objectName] then
            table.insert(list, objectName)
        end
    end
    table.sort(list)
    MTS_FAVORITES_LIST = list
end

local function SaveFavorites()
    RebuildFavoritesListFromSet()
    game.SaveString(FAVORITES_KEY, table.concat(MTS_FAVORITES_LIST, "|"))
end

local function LoadFavorites()
    MTS_FAVORITES_SET = {}
    MTS_FAVORITES_LIST = {}

    local serialized = game.LoadString(FAVORITES_KEY, "")
    if serialized == nil or serialized == "" then
        return
    end

    for objectName in string.gmatch(serialized, "([^|]+)") do
        if spawnablesLookup[objectName] then
            MTS_FAVORITES_SET[objectName] = true
        end
    end

    SaveFavorites()
end

local function IsFavoriteObject(objectName)
    return objectName ~= nil and MTS_FAVORITES_SET[objectName] == true
end

local function EnsureSpawnSettings()
    EnsureAndClampInt(SPAWN_COUNT_KEY, 1, 1, 100)

    local currentMode = game.LoadString(SPAWN_MODE_KEY, "")
    if currentMode ~= "network" and currentMode ~= "local" then
        game.SaveString(SPAWN_MODE_KEY, "network")
    end

    local shapeMode = game.LoadString(SPAWN_SHAPE_KEY, "")
    if shapeMode ~= SPAWN_SHAPE_POINT and shapeMode ~= SPAWN_SHAPE_CIRCLE and shapeMode ~= SPAWN_SHAPE_TIMED_CIRCLE then
        game.SaveString(SPAWN_SHAPE_KEY, SPAWN_SHAPE_POINT)
    end

    local positionMode = game.LoadString(SPAWN_POSITION_MODE_KEY, "")
    if positionMode ~= SPAWN_POSITION_HAND and positionMode ~= SPAWN_POSITION_RAYCAST then
        game.SaveString(SPAWN_POSITION_MODE_KEY, SPAWN_POSITION_HAND)
    end

    EnsureAndClampInt(SPAWN_CIRCLE_RADIUS_KEY, DEFAULT_CIRCLE_RADIUS_TENTHS, CIRCLE_RADIUS_MIN_TENTHS, CIRCLE_RADIUS_MAX_TENTHS)
    EnsureAndClampInt(SPAWN_TIMED_CIRCLE_WAVES_KEY, DEFAULT_TIMED_CIRCLE_WAVES, TIMED_CIRCLE_WAVES_MIN, TIMED_CIRCLE_WAVES_MAX)
    EnsureAndClampInt(SPAWN_TIMED_CIRCLE_INTERVAL_KEY, DEFAULT_TIMED_CIRCLE_INTERVAL_TENTHS, TIMED_CIRCLE_INTERVAL_MIN_TENTHS, TIMED_CIRCLE_INTERVAL_MAX_TENTHS)

    EnsureAndClampInt(UI_SCALE_KEY, DEFAULT_UI_SCALE, UI_SCALE_MIN, UI_SCALE_MAX)

    EnsureAndClampInt(ABILITY_STRENGTH_KEY, 0, -100, 500)
    EnsureAndClampInt(ABILITY_SPEED_KEY, DEFAULT_SPEED_PCT, 25, 300)
    EnsureAndClampInt(ABILITY_CRIT_KEY, 0, -90, 200)
    EnsureAndClampInt(ABILITY_EVASION_KEY, 0, -90, 90)
    EnsureAndClampInt(ABILITY_LUCK_KEY, 0, -100, 200)
    EnsureAndClampInt(ABILITY_DISCOUNT_KEY, 0, -90, 90)
    EnsureAndClampInt(ABILITY_SCALE_KEY, DEFAULT_SCALE_PCT, 50, 250)

    -- Restore search string across sessions
    MTS_SEARCH_STRING = game.LoadString(SEARCH_KEY, "")
    LoadFavorites()

    -- Ensure shoot force setting exists
    EnsureAndClampInt(SHOOT_FORCE_KEY, SHOOT_FORCE_DEFAULT, SHOOT_FORCE_MIN, SHOOT_FORCE_MAX)
end

local function GetOrAddComponent(gameObjectRef, typeName)
    if gameObjectRef == nil then
        return nil
    end
    local typeObj = game.GetType(typeName)
    if typeObj == nil then
        return nil
    end

    local existing = gameObjectRef.GetComponent(typeObj)
    if existing ~= nil then
        return existing
    end
    return gameObjectRef.AddComponent(typeObj)
end

local function SpawnUIPrefab(prefab, position, label)
    if prefab == nil then
        logging.Log("MTS: prefab is nil for '" .. tostring(label) .. "'")
        return nil
    end

    local spawnPos = position
    if spawnPos == nil then
        spawnPos = vector3.zero
    end

    local spawned = nil
    local ok, err = pcall(function()
        spawned = game.QueueInstantiate(prefab, spawnPos, quaternion.identity)
    end)
    if not ok then
        logging.Log("MTS: QueueInstantiate failed for '" .. tostring(label) .. "': " .. tostring(err))
        return nil
    end

    if spawned == nil then
        logging.Log("MTS: instantiate returned nil for '" .. tostring(label) .. "'")
    end
    return spawned
end

local function NormalizeCallbackId(callbackId)
    local id = callbackId
    if id == nil then
        id = "AUTO_" .. tostring(#MTS_CALLBACK_CACHE + 1)
    end

    id = tostring(id)
    if id == "" then
        id = "AUTO_" .. tostring(#MTS_CALLBACK_CACHE + 1)
    end

    return id
end

local function GetCallbackName(callbackCode, callbackId)
    local safeId = NormalizeCallbackId(callbackId)
    local cached = MTS_CALLBACK_CACHE[safeId]
    if cached ~= nil then
        return cached
    end

    local callbackName = AddFuncDynamic(callbackCode, safeId)
    MTS_CALLBACK_CACHE[safeId] = callbackName
    return callbackName
end

local BUTTON_TEXT_TARGET_WIDTH = 50
local BUTTON_TEXT_CHAR_WIDTH_FACTOR = 0.5
local BUTTON_TEXT_MIN_SIZE = 3
local BUTTON_TEXT_MAX_SIZE = 20
local BUTTON_TEXT_DEFAULT_SIZE = 11

local function SetButtonLabel(buttonObject, text)
    if buttonObject == nil then
        return
    end
    local textTransform = buttonObject.transform.Find("Text (TMP)")
    if textTransform == nil then
        return
    end

    local textObj = textTransform.gameObject.GetComponent_TMP_Text_()
    if textObj == nil then
        return
    end

    local rawText = tostring(text or "")
    local displayText = string.gsub(rawText, "_", " ")
    local visibleText = string.gsub(displayText, "<.->", "")
    local visibleChars = string.len(visibleText)
    local fontSize = BUTTON_TEXT_DEFAULT_SIZE
    if visibleChars > 0 then
        local estimatedSize = math.floor(BUTTON_TEXT_TARGET_WIDTH / (visibleChars * BUTTON_TEXT_CHAR_WIDTH_FACTOR))
        fontSize = ClampInt(estimatedSize, BUTTON_TEXT_MIN_SIZE, BUTTON_TEXT_MAX_SIZE)
    end

    if string.find(displayText, "<size=", 1, true) == nil then
        displayText = "<size=" .. tostring(fontSize) .. ">" .. displayText .. "</size>"
    end

    textObj.text = displayText
    if TxtMat ~= nil then
        textObj.material = TxtMat
    end
end

local function SetButtonMarker(buttonObject, active)
    if buttonObject == nil then
        return
    end
    local marker = buttonObject.transform.Find("p")
    if marker ~= nil then
        marker.gameObject.SetActive(active)
    end
end

local function AllocateButtonRearmToken(buttonObject, callbackId)
    local safeId = NormalizeCallbackId(callbackId)
    MTS_BUTTON_REARM_MAP[safeId] = buttonObject
    return safeId
end

function MTS_RearmButtonMarker(token)
    local buttonObject = MTS_BUTTON_REARM_MAP[token]
    if buttonObject == nil then
        return
    end
    SetButtonMarker(buttonObject, false)
end

local function RegisterButtonAction(buttonObject, callbackCode, callbackId)
    if buttonObject == nil then
        return
    end

    if callbackCode == nil then
        logging.Log("MTS: callbackCode is nil for button '" .. tostring(buttonObject.name) .. "'")
        return
    end

    local callbackBaseId = NormalizeCallbackId(callbackId)
    local rearmToken = AllocateButtonRearmToken(buttonObject, callbackBaseId)
    local wrappedCallbackCode = callbackCode .. [[; MTS_RearmButtonMarker("]] .. rearmToken .. [[")]]
    local callbackName = GetCallbackName(wrappedCallbackCode, callbackBaseId .. "_PRESS")
    if callbackName == nil then
        logging.Log("MTS: callbackName is nil for button '" .. tostring(buttonObject.name) .. "'")
        return
    end

    local vibrateType = game.GetType("VibrateOnHighlight")
    if vibrateType ~= nil and buttonObject.GetComponent(vibrateType) == nil then
        buttonObject.AddComponent(vibrateType)
    end

    local pRoot = buttonObject.transform.Find("p")
    if pRoot == nil then
        logging.Log("MTS: missing child 'p' on button '" .. tostring(buttonObject.name) .. "'")
        return
    end
    pRoot.gameObject.SetActive(false)

    local handler = GetOrAddComponent(pRoot.gameObject, "LuaEventHandler")
    if handler == nil then
        logging.Log("MTS: LuaEventHandler unavailable on 'p' for '" .. tostring(buttonObject.name) .. "'")
        return
    end

    handler.RegisterEventHandler(base)
    handler.AddListener("onEnable", callbackName)
    pRoot.gameObject.SetActive(false)
end

local function ApplyStatAddend(statObj, value)
    if statObj == nil then
        return
    end

    statObj.ClearAddend(ABILITY_MOD_KEY)
    if value ~= 0 then
        statObj.RegisterAddend(ABILITY_MOD_KEY, value)
    end
end

local function ApplyStatMultiplier(statObj, value)
    if statObj == nil then
        return
    end

    statObj.ClearMultiplier(ABILITY_MOD_KEY)
    if value ~= 1 then
        statObj.RegisterMultiplier(ABILITY_MOD_KEY, value)
    end
end

local function AdjustSavedInt(key, delta, minValue, maxValue, defaultValue)
    local current = ClampInt(game.LoadInt(key, defaultValue), minValue, maxValue)
    local nextValue = ClampInt(current + delta, minValue, maxValue)
    game.SaveInt(key, nextValue)
    return nextValue
end

local function GetAbilityValues()
    local strength = ClampInt(game.LoadInt(ABILITY_STRENGTH_KEY, 0), -100, 500)
    local speedPct = ClampInt(game.LoadInt(ABILITY_SPEED_KEY, DEFAULT_SPEED_PCT), 25, 300)
    local critPct = ClampInt(game.LoadInt(ABILITY_CRIT_KEY, 0), -90, 200)
    local evasionPct = ClampInt(game.LoadInt(ABILITY_EVASION_KEY, 0), -90, 90)
    local luck = ClampInt(game.LoadInt(ABILITY_LUCK_KEY, 0), -100, 200)
    local discountPct = ClampInt(game.LoadInt(ABILITY_DISCOUNT_KEY, 0), -90, 90)
    local scalePct = ClampInt(game.LoadInt(ABILITY_SCALE_KEY, DEFAULT_SCALE_PCT), 50, 250)

    return strength, speedPct, critPct, evasionPct, luck, discountPct, scalePct
end

local function GetUiScaleValue()
    return ClampInt(game.LoadInt(UI_SCALE_KEY, DEFAULT_UI_SCALE), UI_SCALE_MIN, UI_SCALE_MAX)
end

local function FormatTenths(valueTenths)
    local sign = ""
    local absValue = valueTenths
    if absValue < 0 then
        sign = "-"
        absValue = -absValue
    end
    local whole = math.floor(absValue / 10)
    local fraction = absValue % 10
    return sign .. tostring(whole) .. "." .. tostring(fraction)
end

