    local shape = game.LoadString(SPAWN_SHAPE_KEY, SPAWN_SHAPE_POINT)
    if shape ~= SPAWN_SHAPE_POINT and shape ~= SPAWN_SHAPE_CIRCLE and shape ~= SPAWN_SHAPE_TIMED_CIRCLE then
