    return ClampInt(game.LoadInt(SPAWN_CIRCLE_RADIUS_KEY, DEFAULT_CIRCLE_RADIUS_TENTHS), CIRCLE_RADIUS_MIN_TENTHS, CIRCLE_RADIUS_MAX_TENTHS)
