function MTS_ShowAbilitySummary()
    local strength, speedPct, critPct, evasionPct, luck, discountPct, scalePct = GetAbilityValues()
    local msg = "STR:" .. tostring(strength) ..
        " SPD:" .. tostring(speedPct) .. "%" ..
        " CRT:" .. tostring(critPct) .. "%" ..
        " EVA:" .. tostring(evasionPct) .. "%" ..
        " LUCK:" .. tostring(luck) ..
        " DSC:" .. tostring(discountPct) .. "%" ..
        " SIZE:" .. tostring(scalePct) .. "%"
    game.ShowMessageInWorld(msg, 2.0)
end

function MTS_ApplyAbilitySettings(showMessage)
    local playerLiving = GetPlayerLiving()
    if playerLiving == nil then
        if showMessage then
            game.ShowMessageInWorld("Player not available", 1.0)
        end
        return
    end

    local strength, speedPct, critPct, evasionPct, luck, discountPct, scalePct = GetAbilityValues()

    ApplyStatAddend(playerLiving.PrimaryDamage, strength)
    ApplyStatAddend(playerLiving.SecondaryDamage, strength)
    ApplyStatMultiplier(playerLiving.MoveSpeed, speedPct / 100.0)
    ApplyStatAddend(playerLiving.PrimaryCritChance, critPct / 100.0)
    ApplyStatAddend(playerLiving.SecondaryCritChance, critPct / 100.0)
    ApplyStatAddend(playerLiving.EvasionChance, evasionPct / 100.0)
    ApplyStatAddend(playerLiving.Luck, luck)
    ApplyStatAddend(playerLiving.ShopDiscount, discountPct / 100.0)

    playerLiving.ScaleTo(scalePct / 100.0, 0.15)
    playerLiving.RefreshLuckAndDiscountNetworkVars()

    if showMessage then
        MTS_ShowAbilitySummary()
    end
end

function MTS_ApplyAbilitySettingsSafe(showMessage)
    local ok, err = pcall(MTS_ApplyAbilitySettings, showMessage)
    if not ok then
        logging.Log("MTS: MTS_ApplyAbilitySettings failed: " .. tostring(err))
    end
end

