-- Returns true if text passes the current case-insensitive filter.
local function MatchesSearch(text)
    if MTS_SEARCH_STRING == nil or MTS_SEARCH_STRING == "" then
        return true
    end
    return string.find(string.lower(tostring(text)), string.lower(MTS_SEARCH_STRING), 1, true) ~= nil
end

