function AddFuncDynamic(code, func_name)
    local safeCode = code
    if safeCode == nil or safeCode == "" then
        safeCode = [[ ]]
    end

    local safeFuncName = func_name
    if safeFuncName == nil then
        safeFuncName = "AUTO_" .. tostring(#MTS_CALLBACK_CACHE + 1)
    end
    safeFuncName = tostring(safeFuncName)

    local frontcode = [[return function() ]]
    local endcode = [[ end]]

    local newcode = frontcode .. safeCode .. endcode
    local chunk = base.script.LoadString(newcode)
    if chunk == nil then
        logging.Log("MTS: AddFuncDynamic LoadString failed for '" .. safeFuncName .. "'")
        return nil
    end

    local ok, fnOrErr = pcall(chunk)
    if not ok then
        logging.Log("MTS: AddFuncDynamic compile failed for '" .. safeFuncName .. "': " .. tostring(fnOrErr))
        return nil
    end

    local fn = fnOrErr
    if fn == nil then
        logging.Log("MTS: AddFuncDynamic produced nil function for '" .. safeFuncName .. "'")
        return nil
    end

    -- prefix to avoid collision
    local safeName = "MTS_BTN_" .. safeFuncName
    base.script.Globals[safeName] = fn

    return safeName
end

