local function GetSafeHandSpawnPosition()
    if game.playerController ~= nil and game.playerController.rightHand ~= nil and game.playerController.rightHand.transform ~= nil then
        return game.playerController.rightHand.transform.position
    end

    local playerLiving = GetPlayerLiving()
    if playerLiving ~= nil and playerLiving.transform ~= nil then
        return playerLiving.transform.position + vector3.__new(0, 1.0, 0.4)
    end

    return vector3.zero
end

local function GetSafeForwardDirection()
    if game.playerController ~= nil and game.playerController.rightHand ~= nil and game.playerController.rightHand.transform ~= nil then
        local handForward = game.playerController.rightHand.transform.forward
        local handSqrMagnitude = 0
        local okHandSqr = pcall(function()
            handSqrMagnitude = handForward.sqrMagnitude
        end)
        if handForward ~= nil and okHandSqr and handSqrMagnitude > 0.0001 then
            local normalized = nil
            local okNormalized = pcall(function()
                normalized = handForward.normalized
            end)
            if okNormalized and normalized ~= nil then
                return normalized
            end
        end
    end

    local playerLiving = GetPlayerLiving()
    if playerLiving ~= nil and playerLiving.transform ~= nil then
        local playerForward = playerLiving.transform.forward
        local playerSqrMagnitude = 0
        local okPlayerSqr = pcall(function()
            playerSqrMagnitude = playerForward.sqrMagnitude
        end)
        if playerForward ~= nil and okPlayerSqr and playerSqrMagnitude > 0.0001 then
            local normalized = nil
            local okNormalized = pcall(function()
                normalized = playerForward.normalized
            end)
            if okNormalized and normalized ~= nil then
                return normalized
            end
        end
    end

    return vector3.forward
end

local function SpawnSingleObjectWithMode(objectName, spawnMode, spawnPosition)
    if spawnMode == "local" then
        local okLocal = pcall(function()
            game.SpawnObjectLocal(objectName, spawnPosition)
        end)
        return okLocal
    end

    local okNetwork = pcall(function()
        game.SpawnObjectNetwork(objectName, spawnPosition)
    end)
    if okNetwork then
        return true
    end

    local okFallbackLocal = pcall(function()
        game.SpawnObjectLocal(objectName, spawnPosition)
    end)
    return okFallbackLocal
end

local function BuildCircleSpawnPositions(centerPos, count, radius)
    local positions = {}
    local safeCount = math.max(1, count)
    if safeCount == 1 then
        table.insert(positions, centerPos)
        return positions
    end

    for i = 1, safeCount do
        local angle = ((i - 1) / safeCount) * (math.pi * 2.0)
        local offset = vector3.__new(math.cos(angle) * radius, 0, math.sin(angle) * radius)
        table.insert(positions, centerPos + offset)
    end
    return positions
end

local function SpawnObjectAtPositions(objectName, spawnMode, positions)
    local spawned = 0
    for i = 1, #positions do
        if SpawnSingleObjectWithMode(objectName, spawnMode, positions[i]) then
            spawned = spawned + 1
        end
    end
    return spawned
end

local function SelectClosestRaycastHit(hits, originPos)
    if hits == nil then
        return nil
    end

    local bestPoint = nil
    local bestDistance = nil

    local function TryHit(hit)
        if hit == nil then
            return
        end

        local hitPoint = nil
        local okPoint = pcall(function()
            hitPoint = hit.point
        end)
        if not okPoint or hitPoint == nil then
            return
        end

        local hitDistance = nil
        local okDistance = pcall(function()
            hitDistance = hit.distance
        end)
        if not okDistance or hitDistance == nil then
            local okCalc = pcall(function()
                hitDistance = vector3.Distance(originPos, hitPoint)
            end)
            if not okCalc then
                hitDistance = nil
            end
        end

        if hitDistance ~= nil and hitDistance > 0.05 then
            if bestDistance == nil or hitDistance < bestDistance then
                bestDistance = hitDistance
                bestPoint = hitPoint
            end
        end
    end

    local iterated = false
    local okIpairs = pcall(function()
        for _, hit in ipairs(hits) do
            iterated = true
            TryHit(hit)
        end
    end)

    if not okIpairs or not iterated then
        local length = nil
        local okLength = pcall(function()
            length = hits.Length
        end)

        if okLength and type(length) == "number" and length > 0 then
            for i = 0, length - 1 do
                local hit = nil
                local okZeroIndex = pcall(function()
                    hit = hits[i]
                end)
                if (not okZeroIndex) or hit == nil then
                    pcall(function()
                        hit = hits[i + 1]
                    end)
                end
                TryHit(hit)
            end
        end
    end

    return bestPoint
end

local function TryRaycastSpawnPosition(originPos, forwardDir)
    if physics == nil then
        return nil
    end

    local hits = nil
    local okHits = pcall(function()
        hits = physics.RaycastAll(originPos, forwardDir, 100.0)
    end)
    if not okHits or hits == nil then
        okHits = pcall(function()
            hits = physics.RaycastAll(originPos, forwardDir, 100.0)
        end)
    end
    if not okHits or hits == nil then
        okHits = pcall(function()
            hits = physics.RaycastAll(originPos, forwardDir)
        end)
    end
    if not okHits or hits == nil then
        okHits = pcall(function()
            hits = physics.RaycastAll(originPos, forwardDir)
        end)
    end
    if not okHits or hits == nil then
        return nil
    end

    return SelectClosestRaycastHit(hits, originPos)
end

local function ResolveSpawnCenter()
    local handPos = GetSafeHandSpawnPosition()
    local usedRaycast = false
    local foundRaycastHit = false

    if GetSpawnPositionMode() == SPAWN_POSITION_RAYCAST then
        usedRaycast = true
        local rayPos = TryRaycastSpawnPosition(handPos, GetSafeForwardDirection())
        if rayPos ~= nil then
            foundRaycastHit = true
            return rayPos + vector3.__new(0, 0.05, 0), usedRaycast, foundRaycastHit
        end
    end

    return handPos, usedRaycast, foundRaycastHit
end

function MTS_RunTimedCircleSpawnTick()
    local state = MTS_TimedCircleSpawnState
    if state == nil then
        return
    end

    local waveIndex = state.totalWaves - state.remainingWaves + 1
    local waveRadius = state.baseRadius + ((waveIndex - 1) * state.radiusStep)
    local positions = BuildCircleSpawnPositions(state.centerPos, state.spawnCount, waveRadius)
    local spawnedNow = SpawnObjectAtPositions(state.objectName, state.spawnMode, positions)
    state.totalSpawned = state.totalSpawned + spawnedNow
    state.remainingWaves = state.remainingWaves - 1

    if state.remainingWaves > 0 then
        base.CallFunctionIn("MTS_RunTimedCircleSpawnTick", state.intervalSec)
        return
    end

    game.ShowMessageInWorld("Timed circles done: " .. state.objectName .. " x" .. tostring(state.totalSpawned), 1.5)
    MTS_TimedCircleSpawnState = nil
end

local function StartTimedCircleSpawn(selectedObject, spawnMode, spawnCount, centerPos)
    local totalWaves = GetTimedCircleWaves()
    local baseRadius = GetCircleRadiusValue()
    local intervalSec = GetTimedCircleIntervalTenths() / 10.0
    local radiusStep = math.max(0.25, baseRadius * 0.5)

    MTS_TimedCircleSpawnState = {
        objectName = selectedObject,
        spawnMode = spawnMode,
        spawnCount = spawnCount,
        centerPos = centerPos,
        totalWaves = totalWaves,
        remainingWaves = totalWaves,
        baseRadius = baseRadius,
        radiusStep = radiusStep,
        intervalSec = intervalSec,
        totalSpawned = 0
    }

    game.ShowMessageInWorld("Timed circles started: " .. tostring(totalWaves) .. " waves", 1.0)
    MTS_RunTimedCircleSpawnTick()
end

