-- Try every available API to apply velocity to a spawned object.
-- Returns true if at least one method succeeded without error.
local function TryApplyVelocityToObject(obj, velocityVec)
    if obj == nil then return false end

    -- Method 1: ADVRNetworkRigidbody.RpcForceValueUpdatePosVel (networked, preferred)
    local ok1 = false
    pcall(function()
        local netRb = obj.GetComponent_ADVRNetworkRigidbody_()
        if netRb ~= nil then
            local pos = obj.transform.position
            netRb.RpcForceValueUpdatePosVel(pos, velocityVec)
            ok1 = true
        end
    end)
    if ok1 then return true end

    -- Method 2: ADVRNetworkRigidbody — disable kinematic then set velocity directly
    local ok2 = false
    pcall(function()
        local netRb = obj.GetComponent_ADVRNetworkRigidbody_()
        if netRb ~= nil then
            netRb.syncedIsKinematic = false
            netRb.RpcForceValueUpdateVelocity(velocityVec, vector3.zero)
            ok2 = true
        end
    end)
    if ok2 then return true end

    -- Method 3: Raw Unity Rigidbody via Type lookup
    local ok3 = false
    pcall(function()
        local rbType = game.GetType("UnityEngine.Rigidbody")
        if rbType ~= nil then
            local rb = obj.GetComponent(rbType)
            if rb ~= nil then
                rb.isKinematic = false
                rb.velocity = velocityVec
                ok3 = true
            end
        end
    end)
    if ok3 then return true end

    -- Method 4: Rigidbody via string name (last resort)
    local ok4 = false
    pcall(function()
        local rb = obj.GetComponent("Rigidbody")
        if rb ~= nil then
            rb.velocity = velocityVec
            ok4 = true
        end
    end)
    return ok4
end

-- Manual-move fallback: translates the object forward every tick.
-- Used when the object has no reachable physics component.
function MTS_ShootMoveTick()
    local s = MTS_ShootMoveState
    if s == nil then return end

    s.ticksLeft = s.ticksLeft - 1
    if s.ticksLeft <= 0 then
        MTS_ShootMoveState = nil
        return
    end

    -- Stop if the object was destroyed / deactivated
    local alive = false
    pcall(function()
        alive = s.obj ~= nil and s.obj.activeInHierarchy
    end)
    if not alive then
        MTS_ShootMoveState = nil
        return
    end

    -- Translate the object one step along the shoot direction
    local moved = pcall(function()
        local cur = s.obj.transform.position
        s.obj.transform.position = cur + s.direction * s.stepDist
    end)
    if not moved then
        MTS_ShootMoveState = nil
        return
    end

    base.CallFunctionIn("MTS_ShootMoveTick", SHOOT_TICK_INTERVAL)
end

-- Shoot the selected object from the right hand in the facing direction.
-- SpawnObjectNetwork/Local return the spawned GameObject so we can grab it directly.
function MTS_ShootSelectedObject()
    local selectedObject = game.LoadString(ACTIVE_OBJECT_KEY, NO_SELECTION_VALUE)
    if selectedObject == NO_SELECTION_VALUE then
        game.ShowMessageInWorld("Select an object first (Spawners tab)", 1.25)
        return
    end

    local spawnPos  = GetSafeHandSpawnPosition()
    local direction = GetSafeForwardDirection()
    local force     = GetShootForceValue()
    local velocity  = direction * force
    local spawnMode = game.LoadString(SPAWN_MODE_KEY, "network")

    -- Spawn and capture the returned GameObject
    local spawnedObj = nil

    if spawnMode ~= "local" then
        local ok = pcall(function()
            spawnedObj = game.SpawnObjectNetwork(selectedObject, spawnPos)
        end)
        if not ok then spawnedObj = nil end
    end

    if spawnedObj == nil then
        local ok = pcall(function()
            spawnedObj = game.SpawnObjectLocal(selectedObject, spawnPos)
        end)
        if not ok then
            game.ShowMessageInWorld("Shoot: spawn failed for " .. selectedObject, 1.25)
            return
        end
    end

    if spawnedObj == nil then
        game.ShowMessageInWorld("Shoot: spawn returned nil for " .. selectedObject, 1.25)
        return
    end

    -- Try to apply physics velocity (all known methods, with pcall guards)
    local gotPhysics = TryApplyVelocityToObject(spawnedObj, velocity)

    if gotPhysics then
        game.ShowMessageInWorld("Shot (physics) force:" .. FormatTenths(math.floor(force * 10)) .. " " .. selectedObject, 0.9)
    else
        -- No physics reachable — manually translate the object each tick instead
        MTS_ShootMoveState = nil
        MTS_ShootMoveState = {
            obj       = spawnedObj,
            direction = direction,
            stepDist  = force * SHOOT_TICK_INTERVAL,  -- units per tick
            ticksLeft = SHOOT_MAX_TICKS,
        }
        base.CallFunctionIn("MTS_ShootMoveTick", SHOOT_TICK_INTERVAL)
        game.ShowMessageInWorld("Shot (manual) force:" .. FormatTenths(math.floor(force * 10)) .. " " .. selectedObject, 0.9)
    end
end

