function MTS_SpawnSelectedObject()
    local selectedObject = game.LoadString(ACTIVE_OBJECT_KEY, NO_SELECTION_VALUE)
    if selectedObject == NO_SELECTION_VALUE then
        game.ShowMessageInWorld("Select an object in spawners tab", 1.25)
        return
    end

    local spawnCount = math.max(1, game.LoadInt(SPAWN_COUNT_KEY, 1))
    local spawnMode = game.LoadString(SPAWN_MODE_KEY, "network")
    local spawnShape = GetSpawnShape()
    local spawnCenter, usedRaycast, foundRaycastHit = ResolveSpawnCenter()
    if usedRaycast and not foundRaycastHit then
        game.ShowMessageInWorld("Raycast missed. Using hand position", 1.0)
    end

    if spawnShape == SPAWN_SHAPE_TIMED_CIRCLE then
        StartTimedCircleSpawn(selectedObject, spawnMode, spawnCount, spawnCenter)
        return
    end

    local positions = {}
    if spawnShape == SPAWN_SHAPE_CIRCLE then
        positions = BuildCircleSpawnPositions(spawnCenter, spawnCount, GetCircleRadiusValue())
    else
        for i = 1, spawnCount do
            table.insert(positions, spawnCenter)
        end
    end

    local spawned = SpawnObjectAtPositions(selectedObject, spawnMode, positions)
    game.ShowMessageInWorld("Spawned (" .. spawnShape .. "): " .. selectedObject .. " x" .. tostring(spawned), 1.0)
end
