local function SpawnRelicFromOutcomeNetwork(relicId, spawnPos)
    if relicId == nil or relicId == "" then
        return false
    end

    local spawnedObject = nil
    local okSpawn = pcall(function()
        spawnedObject = game.SpawnObjectNetwork(RELIC_SPAWN_OBJECT_ID, spawnPos)
    end)
    if not okSpawn or spawnedObject == nil then
        return false
    end

    if not ChangeRelicOutcome(spawnedObject, relicId) then
        return false
    end

    local itemUpgrade = nil
    local okItemUpgrade = pcall(function()
        itemUpgrade = spawnedObject.GetComponent_ItemUpgrade_()
    end)
    if not okItemUpgrade or itemUpgrade == nil then
        return false
    end

    local okRoll = pcall(function()
        itemUpgrade.RollItem()
    end)
    return okRoll
end

function MTS_SpawnRandomRelicFromClass()
    local relicIds = GetAllRelicIdsFromRelicsClass()
    if #relicIds == 0 then
        game.ShowMessageInWorld("No relics found in relics class", 1.25)
        return
    end

    local randomIndex = math.random(1, #relicIds)
    local relicId = relicIds[randomIndex]
    local spawnPos = GetAbilitySpawnAnchor()
    local okSpawn = SpawnRelicFromOutcomeNetwork(relicId, spawnPos)

    if not okSpawn then
        game.ShowMessageInWorld("Failed to spawn relic " .. tostring(relicId), 1.25)
        return
    end

    game.ShowMessageInWorld("Spawned relic: " .. tostring(relicId), 1.25)
end

function MTS_SpawnAllRelicsFromClass()
    local relicIds = GetAllRelicIdsFromRelicsClass()
    if #relicIds == 0 then
        game.ShowMessageInWorld("No relics found in relics class", 1.25)
        return
    end

    local anchorPos = GetAbilitySpawnAnchor()
    local columns = math.max(1, math.floor(math.sqrt(#relicIds)))
    local spacing = 0.45
    local spawnedCount = 0

    for i = 1, #relicIds do
        local xIndex = (i - 1) % columns
        local zIndex = math.floor((i - 1) / columns)
        local xOffset = (xIndex - ((columns - 1) * 0.5)) * spacing
        local zOffset = zIndex * spacing
        local spawnPos = anchorPos + vector3.__new(xOffset, 0.0, zOffset)

        if SpawnRelicFromOutcomeNetwork(relicIds[i], spawnPos) then
            spawnedCount = spawnedCount + 1
        end
    end

    game.ShowMessageInWorld("Spawned relics: " .. tostring(spawnedCount) .. "/" .. tostring(#relicIds), 2.0)
end

