local function GetPitDropPosition()
    local fallbackPos = GetAbilitySpawnAnchor()
    if game.currentWorldGenerator == nil then
        return fallbackPos, false
    end

    local playerLiving = GetPlayerLiving()
    if playerLiving == nil or playerLiving.transform == nil then
        return fallbackPos, false
    end

    local room = nil
    local okRoom = pcall(function()
        room = game.currentWorldGenerator.GetRoomAtRealPos(playerLiving.transform.position)
    end)
    if not okRoom or room == nil then
        return fallbackPos, false
    end

    local tiles = room.baseTiles
    if tiles ~= nil then
        for _, tile in ipairs(tiles) do
            if tile ~= nil then
                local tilePos = nil
                local okPos = pcall(function()
                    tilePos = tile.GetWorldPos()
                end)
                if okPos and tilePos ~= nil then
                    local isPit = false

                    local okSolid, isSolid = pcall(function()
                        return tile.IsGroundSolid()
                    end)
                    if okSolid and isSolid == false then
                        isPit = true
                    end

                    if not isPit and tile.ground ~= nil then
                        local groundId = string.lower(tostring(tile.ground))
                        if string.find(groundId, "pit", 1, true) ~= nil then
                            isPit = true
                        end
                    end

                    if isPit then
                        return tilePos + vector3.__new(0, 1.2, 0), true
                    end
                end
            end
        end
    end

    local roomBasePos = nil
    local okRoomBase = pcall(function()
        roomBasePos = room.GetWorldPosBase()
    end)
    if okRoomBase and roomBasePos ~= nil then
        return roomBasePos + vector3.__new(0, 1.2, 0), false
    end

    return fallbackPos, false
end

