function MTS_GivePitFriendAndDragonRain()
    local gavePitFriend = pcall(function()
        GiveRelic(RELIC_PIT_FRIEND_ID)
    end)

    local pitPos, foundPit = GetPitDropPosition()
    local spawnedCount = 0
    local gridSize = 10
    local spacing = 0.5

    for i = 1, 100 do
        local xIndex = (i - 1) % gridSize
        local zIndex = math.floor((i - 1) / gridSize)

        local xOffset = (xIndex - 4.5) * spacing + ((math.random() - 0.5) * 0.2)
        local zOffset = (zIndex - 4.5) * spacing + ((math.random() - 0.5) * 0.2)
        local yOffset = 1.0 + (math.random() * 2.0)
        local spawnPos = pitPos + vector3.__new(xOffset, yOffset, zOffset)

        local okNetwork = pcall(function()
            game.SpawnObjectNetwork(FOOD_DRAGONFRUIT_ID, spawnPos)
        end)

        if not okNetwork then
            local okLocal = pcall(function()
                game.SpawnObjectLocal(FOOD_DRAGONFRUIT_ID, spawnPos)
            end)
            if okLocal then
                spawnedCount = spawnedCount + 1
            end
        else
            spawnedCount = spawnedCount + 1
        end
    end

    local pitText = "pit"
    if not foundPit then
        pitText = "fallback"
    end

    game.ShowMessageInWorld("Pit friend: " .. tostring(gavePitFriend) .. " | dragonfruit: " .. tostring(spawnedCount) .. " (" .. pitText .. ")", 2.0)
end

