    MTS_UpdateSearchDisplay()
    MTS_FAVORITES_SET = {}
    MTS_FAVORITES_LIST = {}
    game.SaveString(FAVORITES_KEY, "")

    game.ShowMessageInWorld("All MTS settings reset", 1.25)
end

function MTS_ClearListButtons()
    for i = 1, #MTS_LIST_BUTTONS do
        local buttonObj = MTS_LIST_BUTTONS[i]
        if buttonObj ~= nil then
            game.Delete(buttonObj)
        end
    end

    MTS_LIST_BUTTONS = {}
    NewButtons = MTS_LIST_BUTTONS
end

function MTS_CreateListButton(buttonLabel, callbackCode, callbackId)
    if MTS_ButtonTemplate == nil or MTS_ListRoot == nil then
        return nil
    end

    local newButton = SpawnUIPrefab(MTS_ButtonTemplate, vector3.zero, "ListButton:" .. tostring(buttonLabel))
    if newButton == nil then
        return nil
    end

    local newTransform = newButton.transform
    local templateTransform = MTS_ButtonTemplate.transform

    local parentedWithNoWorldSpace = false
    local okParent = pcall(function()
        newTransform.SetParent(MTS_ListRoot.transform, false)
        parentedWithNoWorldSpace = true
    end)
    if not okParent or not parentedWithNoWorldSpace then
        newTransform.SetParent(MTS_ListRoot.transform)
    end

    local templateScale = templateTransform.localScale
    local templatePos = templateTransform.localPosition
    newTransform.localScale = vector3.__new(templateScale.x, templateScale.y, templateScale.z)
    newTransform.localPosition = vector3.__new(templatePos.x, templatePos.y, templatePos.z)
    newTransform.localRotation = templateTransform.localRotation

    newButton.SetActive(true)
    SetButtonMarker(newButton, false)
    local favoriteToggle = newTransform.Find("Fav_BT")
    if favoriteToggle ~= nil then
        favoriteToggle.gameObject.SetActive(false)
    end

    SetButtonLabel(newButton, buttonLabel)
    local okRegister, errRegister = pcall(RegisterButtonAction, newButton, callbackCode, callbackId)
    if not okRegister then
        logging.Log("MTS: failed to wire list button '" .. tostring(buttonLabel) .. "': " .. tostring(errRegister))
    end

    table.insert(MTS_LIST_BUTTONS, newButton)
    NewButtons = MTS_LIST_BUTTONS
    return newButton
end

local function ConfigureFavoriteToggleForButton(listButton, objectName)
    if listButton == nil or objectName == nil then
        return
    end

    local favoriteToggle = listButton.transform.Find("Fav_BT")
    if favoriteToggle == nil or favoriteToggle.gameObject == nil then
        return
    end

    favoriteToggle.gameObject.SetActive(true)

    local xMarker = favoriteToggle.Find("X")
    if xMarker ~= nil and xMarker.gameObject ~= nil then
        xMarker.gameObject.SetActive(IsFavoriteObject(objectName))
    end

    local safeObjName = string.gsub(objectName, "\"", "\\\"")
    local callbackCode = [[MTS_ToggleFavoriteObject("]] .. safeObjName .. [[")]]
    local callbackId = "FAV_TOGGLE_" .. objectName
    pcall(RegisterButtonAction, favoriteToggle.gameObject, callbackCode, callbackId)
end

local function CreateSpawnObjectListButton(objectName)
    local safeObjName = string.gsub(objectName, "\"", "\\\"")
    local callbackCode = [[MTS_SetSelectedObject("]] .. safeObjName .. [[")]]
    local button = MTS_CreateListButton(objectName, callbackCode, "OBJ_" .. objectName)
    ConfigureFavoriteToggleForButton(button, objectName)
end

