local function RefreshTabVisuals()
    MTS_TabVisualUpdateLock = true
    -- `p` must stay disabled until the engine enables it on press.
    SetButtonMarker(MTS_TabButtons[TAB_SPAWNERS], false)
    if MTS_TabButtons[TAB_FAVORITES] ~= nil then
        SetButtonMarker(MTS_TabButtons[TAB_FAVORITES], false)
    end
    if MTS_TabButtons[TAB_RELICS] ~= nil then
        SetButtonMarker(MTS_TabButtons[TAB_RELICS], false)
    end
    if MTS_TabButtons[TAB_SOUNDS] ~= nil then
        SetButtonMarker(MTS_TabButtons[TAB_SOUNDS], false)
    end
    SetButtonMarker(MTS_TabButtons[TAB_ABILITIES], false)
    SetButtonMarker(MTS_TabButtons[TAB_SETTINGS], false)
    MTS_TabVisualUpdateLock = false
end

function MTS_ShowTab(tabName, showToast, forceRebuild)
    if MTS_TabVisualUpdateLock then
        return
    end

    if tabName ~= TAB_SPAWNERS and tabName ~= TAB_FAVORITES and tabName ~= TAB_RELICS and tabName ~= TAB_SOUNDS and tabName ~= TAB_ABILITIES and tabName ~= TAB_SETTINGS then
        return
    end
    if MTS_ListRoot == nil or MTS_ButtonTemplate == nil then
        return
    end

    if (not forceRebuild) and MTS_ACTIVE_TAB == tabName and #MTS_LIST_BUTTONS > 0 then
        if showToast == nil or showToast then
            game.ShowMessageInWorld("Tab: " .. tabName, 0.5)
        end
        return
    end

    MTS_ACTIVE_TAB = tabName
    MTS_ClearListButtons()

    if tabName == TAB_SPAWNERS then
        BuildSpawnersTab()
    elseif tabName == TAB_FAVORITES then
        BuildFavoritesTab()
    elseif tabName == TAB_RELICS then
        BuildRelicsTab()
    elseif tabName == TAB_SOUNDS then
        BuildSoundsTab()
    elseif tabName == TAB_ABILITIES then
        BuildAbilitiesTab()
    elseif tabName == TAB_SETTINGS then
        BuildSettingsTab()
    end

    RefreshTabVisuals()

    if showToast == nil or showToast then
        game.ShowMessageInWorld("Tab: " .. tabName, 0.75)
    end
end

function ADVR.onSpawnInHomeBase()
    local ok, err = pcall(function()
        EnsureSpawnSettings()

        if hsent ~= true then
            hsent = true
            local menuPrefab = base.GetObjectFromAssetBundle("ModdingCanvas", "UnityEngine.GameObject")
            if menuPrefab == nil then
                logging.Log("MTS: asset bundle object 'ModdingCanvas' was nil")
                hsent = false
                return
            end

            Menu = SpawnUIPrefab(menuPrefab, vector3.zero, "ModdingCanvas")
            if Menu == nil then
                hsent = false
                return
            end

            if game.mainMenu == nil or game.mainMenu.gameObject == nil then
                logging.Log("MTS: game.mainMenu.gameObject is nil")
                hsent = false
                return
            end

            MainMenu = game.mainMenu.gameObject

            local txtMatRoot = MainMenu.transform.Find("Scaler/MainMenuCanvas/EA Infos/TextThankYou")
            if txtMatRoot ~= nil and txtMatRoot.gameObject ~= nil then
                local txtCmp = txtMatRoot.gameObject.GetComponent_TMP_Text_()
                if txtCmp ~= nil then
                    TxtMat = txtCmp.fontMaterial
                end
            else
                logging.Log("MTS: missing Scaler/MainMenuCanvas/EA Infos/TextThankYou for font material")
            end

            local mainCanvasRoot = MainMenu.transform.Find("Scaler/MainMenuCanvas")
            if mainCanvasRoot == nil or mainCanvasRoot.gameObject == nil then
                logging.Log("MTS: missing Scaler/MainMenuCanvas")
                hsent = false
                return
            end

            Canvas = mainCanvasRoot.gameObject
            newcnv = SpawnUIPrefab(Canvas, vector3.zero, "MainMenuCanvasClone")
            if newcnv == nil then
                hsent = false
                return
            end

            local newCanvasChildCount = newcnv.transform.GetChildCount()
            for i = newCanvasChildCount - 1, 0, -1 do
                local child = newcnv.transform.GetChild(i)
                if child ~= nil then
                    game.Delete(child.gameObject)
                end
            end

            local oldCanvasRoot = Menu.transform.Find("Canvas")
            if oldCanvasRoot == nil or oldCanvasRoot.gameObject == nil then
                logging.Log("MTS: missing Canvas under ModdingCanvas root")
                hsent = false
                return
            end

            OldCnv = oldCanvasRoot.gameObject
            local oldChildren = {}
            local oldCanvasChildCount = OldCnv.transform.GetChildCount()
            for i = 0, oldCanvasChildCount - 1 do
                local child = OldCnv.transform.GetChild(i)
                if child ~= nil then
                    table.insert(oldChildren, child)
                end
            end
            for i = 1, #oldChildren do
                local child = oldChildren[i]
                child.SetParent(newcnv.transform)
                child.SetSiblingIndex(i - 1)
            end

            newcnv.transform.SetParent(Menu.transform)
            game.Delete(OldCnv)

            MTS_ListRoot = newcnv.Find("ButtonArea/Viewport/Content")
            if MTS_ListRoot ~= nil then
                MTS_ButtonTemplate = MTS_ListRoot.Find("Bttn_Temp")
            end

            MTS_TabButtons[TAB_SPAWNERS] = newcnv.Find("Spwn_BT")
            MTS_TabButtons[TAB_FAVORITES] = newcnv.Find("Fav_TBBT")
            MTS_TabButtons[TAB_RELICS] = newcnv.Find("Relic_BT")
            MTS_TabButtons[TAB_SOUNDS] = newcnv.Find("Sounds_BT")
            MTS_TabButtons[TAB_ABILITIES] = newcnv.Find("Abl_BT")
            MTS_TabButtons[TAB_SETTINGS] = newcnv.Find("Stt_BT")

            if MTS_ListRoot == nil or MTS_ButtonTemplate == nil or MTS_TabButtons[TAB_SPAWNERS] == nil or MTS_TabButtons[TAB_ABILITIES] == nil or MTS_TabButtons[TAB_SETTINGS] == nil then
                logging.Log("MTS: Missing required objects for ModdingCanvas layout")
                hsent = false
                return
            end
            if MTS_TabButtons[TAB_RELICS] == nil then
                logging.Log("MTS: Relic_BT not found - relics tab will be unavailable")
            end
            if MTS_TabButtons[TAB_FAVORITES] == nil then
                logging.Log("MTS: Fav_TBBT not found - favorites tab will be unavailable")
            end
            if MTS_TabButtons[TAB_SOUNDS] == nil then
                logging.Log("MTS: Sounds_BT not found - sounds tab will be unavailable")
            end

            MTS_ButtonTemplate.SetActive(false)
            SetButtonMarker(MTS_TabButtons[TAB_SPAWNERS], false)
            if MTS_TabButtons[TAB_FAVORITES] ~= nil then
                SetButtonMarker(MTS_TabButtons[TAB_FAVORITES], false)
            end
            if MTS_TabButtons[TAB_RELICS] ~= nil then
                SetButtonMarker(MTS_TabButtons[TAB_RELICS], false)
            end
            if MTS_TabButtons[TAB_SOUNDS] ~= nil then
                SetButtonMarker(MTS_TabButtons[TAB_SOUNDS], false)
            end
            SetButtonMarker(MTS_TabButtons[TAB_ABILITIES], false)
            SetButtonMarker(MTS_TabButtons[TAB_SETTINGS], false)

            local okSpawn, errSpawn = pcall(RegisterButtonAction, MTS_TabButtons[TAB_SPAWNERS], [[MTS_ShowTab("spawners")]], "TAB_SPAWNERS")
            if not okSpawn then
                logging.Log("MTS: failed to wire Spwn_BT: " .. tostring(errSpawn))
            end
            if MTS_TabButtons[TAB_FAVORITES] ~= nil then
                local okFavorites, errFavorites = pcall(RegisterButtonAction, MTS_TabButtons[TAB_FAVORITES], [[MTS_ShowTab("favorites")]], "TAB_FAVORITES")
                if not okFavorites then
                    logging.Log("MTS: failed to wire Fav_TBBT: " .. tostring(errFavorites))
                end
            end
            if MTS_TabButtons[TAB_RELICS] ~= nil then
                local okRelics, errRelics = pcall(RegisterButtonAction, MTS_TabButtons[TAB_RELICS], [[MTS_ShowTab("relics")]], "TAB_RELICS")
                if not okRelics then
                    logging.Log("MTS: failed to wire Relic_BT: " .. tostring(errRelics))
                end
            end
            if MTS_TabButtons[TAB_SOUNDS] ~= nil then
                local okSounds, errSounds = pcall(RegisterButtonAction, MTS_TabButtons[TAB_SOUNDS], [[MTS_ShowTab("sounds")]], "TAB_SOUNDS")
                if not okSounds then
                    logging.Log("MTS: failed to wire Sounds_BT: " .. tostring(errSounds))
                end
            end
            local okAbilities, errAbilities = pcall(RegisterButtonAction, MTS_TabButtons[TAB_ABILITIES], [[MTS_ShowTab("abilities")]], "TAB_ABILITIES")
            if not okAbilities then
                logging.Log("MTS: failed to wire Abl_BT: " .. tostring(errAbilities))
            end
            local okSettings, errSettings = pcall(RegisterButtonAction, MTS_TabButtons[TAB_SETTINGS], [[MTS_ShowTab("settings")]], "TAB_SETTINGS")
            if not okSettings then
                logging.Log("MTS: failed to wire Stt_BT: " .. tostring(errSettings))
            end

            MTS_ShowTab(TAB_SPAWNERS, false)

            -- ------------------------------------------------
            -- SEARCH BAR  (Start_Search_BT toggles keyboard)
            -- ------------------------------------------------
            local searchBarT = newcnv.Find("SearchBar")
            if searchBarT ~= nil then
                local startSearchT = searchBarT.Find("Start_Search_BT")
                if startSearchT ~= nil then
                    -- Grab TMP for live search display
                    local tmpT = startSearchT.Find("Text (TMP)")
                    if tmpT ~= nil then
                        pcall(function()
                            MTS_SearchDisplayTMP = tmpT.gameObject.GetComponent_TMP_Text_()
                        end)
                    end
                    if TxtMat ~= nil and MTS_SearchDisplayTMP ~= nil then
                        pcall(function() MTS_SearchDisplayTMP.material = TxtMat end)
                    end
                    -- Wire button to toggle keyboard visibility
                    pcall(RegisterButtonAction, startSearchT.gameObject,
                        [[MTS_ToggleKeyboard()]],
                        "SEARCH_TOGGLE_KB")
                    -- Initialise display text
                    MTS_UpdateSearchDisplay()
                else
                    logging.Log("MTS: SearchBar/Start_Search_BT not found")
                end
            else
                logging.Log("MTS: SearchBar not found")
            end

            -- ------------------------------------------------
            -- KEYBOARD  (inactive on start; each key appends)
            -- ------------------------------------------------
            local kbT = newcnv.Find("Keyboard")
            if kbT ~= nil then
                MTS_KeyboardObj = kbT.gameObject
                MTS_KeyboardObj.SetActive(false)   -- ensure hidden at start

                -- Wire all letter keys  (each has Text (TMP) + p child)
                local allKeys = {
                    "Q","W","E","R","T","Y","U","I","O","P",
                    "A","S","D","F","G","H","J","K","L",
                    "Z","X","C","V","B","N","M",
                    "Spc"   -- space key
                }
                for _, keyName in ipairs(allKeys) do
                    local keyT = kbT.transform.Find(keyName).gameObject
                    if keyT ~= nil then
                        local char = (keyName == "Spc") and " " or keyName
                        local code = [[MTS_AppendSearchChar("]] .. char .. [[")]]
                        pcall(RegisterButtonAction, keyT.gameObject, code, "KEY_" .. keyName)
                    else
                        logging.Log("MTS: keyboard key not found: " .. keyName)
                    end
                end

                -- Backspace key — try likely names from the prefab
                local bkspNames = {"Bksp", "Backspace", "Back", "Del", "Delete", "BK"}
                for _, bname in ipairs(bkspNames) do
                    local bkspT = kbT.transform.Find(bname).gameObject
                    if bkspT ~= nil then
                        pcall(RegisterButtonAction, bkspT.gameObject,
                            [[MTS_BackspaceSearch()]],
                            "KEY_BKSP")
                        break
                    end
                end
            else
                logging.Log("MTS: Keyboard GameObject not found")
            end

            -- ------------------------------------------------
            -- MINI TABS  (MiniTB-1, MiniTB-2)
            -- Trigger is on the child named "Turn" (p lives there)
            -- ------------------------------------------------
            local miniTb1T = newcnv.Find("MiniTB-1")
            local miniTb2T = newcnv.Find("MiniTB-2")
            if miniTb1T ~= nil then
                local turnT = miniTb1T.Find("Turn")
                if turnT ~= nil then
                    MTS_MiniTabButtons[1] = turnT.gameObject
                    -- Placeholder: clear filter (Tab 1 = show all)
                    pcall(RegisterButtonAction, turnT.gameObject,
                        [[MTS_ClearSearchFilter(); game.ShowMessageInWorld("Mini tab 1", 0.75)]],
                        "MINITAB_1")
                end
            end
            if miniTb2T ~= nil then
                local turnT = miniTb2T.Find("Turn")
                if turnT ~= nil then
                    MTS_MiniTabButtons[2] = turnT.gameObject
                    -- Placeholder action for Mini Tab 2
                    pcall(RegisterButtonAction, turnT.gameObject,
                        [[game.ShowMessageInWorld("Mini tab 2", 0.75)]],
                        "MINITAB_2")
                end
            end

            base.RemoveComponent(newcnv, "CanvasScaler")
            base.CallFunctionIn("AddCnvScl", 2.5)

            Menu.transform.SetParent(game.playerController.leftHand.transform)
            Menu.transform.localPosition = vector3.__new(0, 0.5, 0)
            local menuHandler = GetOrAddComponent(Menu, "LuaEventHandler")
            if menuHandler ~= nil then
                menuHandler.RegisterEventHandler(base)
            end
            newcnv.transform.rotation = quaternion.identity
            base.CallFunctionOnRepeat("gameUpdate", mathf.Infinity, 0.1)
        end
    end)

    if not ok then
        logging.Log("MTS: onSpawnInHomeBase failed: " .. tostring(err))
        hsent = false
    end
end

function AddCnvScl()
    if newcnv == nil then
        return
    end

    local scalerType = game.GetType("UnityEngine.UI.CanvasScaler")
    if scalerType ~= nil and newcnv.GetComponent(scalerType) == nil then
        newcnv.AddComponent(scalerType)
    end

    MTS_ApplyUiScale()
end

function gameUpdate()
    game.playerController.UiPointerEnabled = true
end

function ADVR.onButtonPress(id, prs)
    if prs and id == "leftButtonOne" and game.LoadBool(SPAWN_HOTKEY_KEY, true) then
        -- When shoot mode is on, the left trigger shoots instead of placing
        if MTS_GetShootMode() then
            MTS_ShootSelectedObject()
        else
            MTS_SpawnSelectedObject()
        end
    end
end
